        qc_inspection_date: this.fmtYmd(v.qcInspectionDate),
        actual_etd: this.fmtYmd(v.actualEtd)
      })
      .subscribe({
        next: () => {
          this.saving = false;
          this.snackBar.open('Saved', 'Dismiss', { duration: 3000 });
          const id = v.prodOrderId;
          const row = this.prodOrders.find((o) => o.id === id);
          if (row) {
            row.material_arrival_date = this.fmtYmd(v.materialArrivalDate);
            row.mass_prod_start_date = this.fmtYmd(v.massProdStartDate);
            row.assembly_start_date = this.fmtYmd(v.assemblyStartDate);
            row.actual_prod_complete = this.fmtYmd(v.actualProdComplete);
            row.packing_start_date = this.fmtYmd(v.packingStartDate);
            row.qc_inspection_date = this.fmtYmd(v.qcInspectionDate);
            row.actual_etd = this.fmtYmd(v.actualEtd);
          }
        },
        error: (err) => {
          this.saving = false;
          const msg = err?.error?.message || 'Save failed';
          this.snackBar.open(msg, 'Dismiss', { duration: 6000 });
        }
