  onSubmitSampleOffer(): void {
    if (!this.factoryForm.get('factoryId')?.value) {
      this.snackBar.open('Select a factory before entering a sample offer', 'Dismiss', { duration: 4000 });
      return;
    }
    if (this.sampleOfferForm.invalid) {
