const jwt = require('jsonwebtoken');
const { generateKeyPairSync } = require('crypto');

describe('auth helper', () => {
  let privateKey;

  beforeEach(() => {
    jest.resetModules();
    const pair = generateKeyPairSync('rsa', { modulusLength: 2048 });
    privateKey = pair.privateKey.export({ type: 'pkcs1', format: 'pem' });
    process.env.JWT_PUBLIC_KEY = pair.publicKey.export({ type: 'pkcs1', format: 'pem' });
  });

  afterEach(() => {
    delete process.env.JWT_PUBLIC_KEY;
  });

  it('returns decoded user info from a valid RS256 token', async () => {
    const { getUserInfo } = require('../../helpers/auth');
    const token = jwt.sign(
      { user_id: 8, name: 'Factory User', role: 'vendor', factory_id: 321 },
      privateKey,
      { algorithm: 'RS256' }
    );

    const decoded = await getUserInfo(token);

    expect(decoded).toMatchObject({
      user_id: 8,
      name: 'Factory User',
      role: 'vendor',
      factory_id: 321
    });
  });

  it('returns false for an invalid token', async () => {
    const { getUserInfo } = require('../../helpers/auth');

    await expect(getUserInfo('not-a-token')).resolves.toBe(false);
  });
});

