// Frontend mirror of the backend sample status state machine
// (designflow-tracking/helpers/sampleStatus.js). Used for labels and to PREVIEW
// the next status in the check-in/out dialog. The SERVER remains authoritative —
// it derives and validates the real transition.

export type SampleDirection = 'inbound' | 'outbound';
export type SampleEventType = 'check_in' | 'check_out' | 'ship' | 'receive' | 'status_change';

export const ORIGINS = ['factory_request', 'factory_offer', 'usa_bought'] as const;
export const OFFICES = ['Ningbo', 'NYC'] as const;
export const SAMPLE_STOPS = ['Factory', 'Ningbo', 'NYC'] as const;
export const SHARED_EXTRAS = ['cancelled', 'on_hold', 'damaged', 'approved'] as const;
export const TERMINAL_EXTRAS = ['cancelled'] as const;

export const ORIGIN_DEFAULTS: Record<string, { direction: SampleDirection; initialStatus: string }> = {
  factory_request: { direction: 'inbound', initialStatus: 'requested' },
  factory_offer: { direction: 'inbound', initialStatus: 'requested' },
  usa_bought: { direction: 'outbound', initialStatus: 'nyc_requested' }
};

export const BACKBONE: Record<SampleDirection, string[]> = {
  inbound: ['requested', 'shipped', 'ningbo_checked_in', 'ningbo_checked_out', 'nyc_checked_in'],
  outbound: ['nyc_requested', 'nyc_checked_out', 'ningbo_checked_in', 'ningbo_checked_out', 'sent_to_factory']
};

interface TransitionRule {
  from: string;
  eventType: SampleEventType;
  office: string | null;
  to: string;
}

export const TRANSITIONS: Record<SampleDirection, TransitionRule[]> = {
  inbound: [
    { from: 'requested', eventType: 'ship', office: null, to: 'shipped' },
    { from: 'shipped', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
    { from: 'ningbo_checked_out', eventType: 'check_in', office: 'NYC', to: 'nyc_checked_in' }
  ],
  outbound: [
    { from: 'nyc_requested', eventType: 'check_out', office: 'NYC', to: 'nyc_checked_out' },
    { from: 'nyc_checked_out', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
    { from: 'ningbo_checked_out', eventType: 'ship', office: 'Ningbo', to: 'sent_to_factory' }
  ]
};

// Human-readable labels for statuses (grid + dialogs).
export const STATUS_LABELS: Record<string, string> = {
  requested: 'Requested',
  shipped: 'Shipped',
  ningbo_checked_in: 'Ningbo — Checked In',
  ningbo_checked_out: 'Ningbo — Checked Out',
  nyc_checked_in: 'NYC — Checked In',
  nyc_requested: 'NYC — Requested',
  nyc_checked_out: 'NYC — Checked Out',
  sent_to_factory: 'Sent to Factory',
  cancelled: 'Cancelled',
  on_hold: 'On Hold',
  damaged: 'Damaged',
  approved: 'Approved'
};

export function statusLabel(status: string): string {
  return STATUS_LABELS[status] || status || '';
}

// "inbound"/"outbound" is confusing on its own — show the sample's journey instead.
export function directionLabel(direction: string): string {
  if (direction === 'inbound') return 'Factory → NYC';
  if (direction === 'outbound') return 'NYC → Factory';
  return direction || '';
}

// A box ships between the two offices. Express it as a route, not inbound/outbound.
// A box's route also fixes which sample direction it can carry.
export interface BoxRoute {
  value: string;          // leg_type
  label: string;          // user-facing route
  direction: SampleDirection;
  origin: string;
  dest: string;
}
export const BOX_ROUTES: BoxRoute[] = [
  { value: 'ningbo_to_nyc', label: 'Ningbo → NYC', direction: 'inbound', origin: 'Ningbo', dest: 'NYC' },
  { value: 'nyc_to_ningbo', label: 'NYC → Ningbo', direction: 'outbound', origin: 'NYC', dest: 'Ningbo' }
];

// Render a box's route from its stored origin/dest (falls back to direction).
export function boxRouteLabel(box: any): string {
  if (box && box.origin_office && box.dest_office) return `${box.origin_office} → ${box.dest_office}`;
  const r = BOX_ROUTES.find(x => x.direction === (box && box.direction));
  return r ? r.label : ((box && box.direction) || '');
}

// The leg_type to record when adding samples to a box, derived from its route.
export function legTypeForBox(box: any): string {
  return (box && box.direction === 'outbound') ? 'nyc_to_ningbo' : 'ningbo_to_nyc';
}

export function isBackboneStatus(direction: SampleDirection, status: string): boolean {
  return (BACKBONE[direction] || []).includes(status);
}

export interface DeriveResult {
  ok: boolean;
  toStatus?: string;
  error?: string;
}

// Mirror of backend deriveToStatus — for client-side preview/validation only.
export function deriveToStatus(opts: {
  direction: SampleDirection;
  currentStatus: string;
  office?: string | null;
  eventType: SampleEventType;
  requestedToStatus?: string | null;
}): DeriveResult {
  const { direction, currentStatus, office = null, eventType, requestedToStatus = null } = opts;

  if (!BACKBONE[direction]) return { ok: false, error: `Unknown direction "${direction}"` };
  if ((TERMINAL_EXTRAS as readonly string[]).includes(currentStatus)) {
    return { ok: false, error: `Sample is ${currentStatus}; no further changes allowed` };
  }

  if (eventType === 'status_change') {
    if (!requestedToStatus) return { ok: false, error: 'status_change requires a to_status' };
    if ((SHARED_EXTRAS as readonly string[]).includes(requestedToStatus)) {
      if (requestedToStatus === currentStatus) return { ok: false, error: `Sample already ${currentStatus}` };
      return { ok: true, toStatus: requestedToStatus };
    }
    if (currentStatus === 'on_hold' && isBackboneStatus(direction, requestedToStatus)) {
      return { ok: true, toStatus: requestedToStatus };
    }
    return { ok: false, error: `Illegal status_change to "${requestedToStatus}" from "${currentStatus}"` };
  }

  const rule = (TRANSITIONS[direction] || []).find(r =>
    r.from === currentStatus &&
    r.eventType === eventType &&
    (r.office === null || r.office === office)
  );
  if (!rule) {
    return { ok: false, error: `No ${eventType} transition from "${currentStatus}"` + (office ? ` at ${office}` : '') };
  }
  return { ok: true, toStatus: rule.to };
}

