import { Component, Inject } from '@angular/core';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import {
  OFFICES, SHARED_EXTRAS, SampleEventType, SampleDirection,
  deriveToStatus, statusLabel, directionLabel
} from '../helpers/sample.status';

export interface EventDialogData {
  sample_id_pk: number;
  sample_name?: string;
  direction: SampleDirection;
  status: string;
  office_location?: string;
}

// Check-in / check-out (and flag) dialog. The client previews the derived next
// status; the server is authoritative and may still reject.
@Component({
  selector: 'sample-event-dialog',
  standalone: false,
  templateUrl: './event-dialog.component.html',
  styleUrls: ['./event-dialog.component.scss']
})
export class EventDialogComponent {
  offices = OFFICES;
  extras = SHARED_EXTRAS;

  eventType: SampleEventType = 'check_in';
  office: string | null = null;
  toStatus: string | null = null; // only for status_change
  notes = '';

  preview: { ok: boolean; toStatus?: string; error?: string } = { ok: false };

  constructor(
    public dialogRef: MatDialogRef<EventDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: EventDialogData
  ) {
    this.office = data.office_location || null;
    this.recompute();
  }

  statusLabel = statusLabel;
  directionLabel = directionLabel;

  get currentLabel(): string { return statusLabel(this.data.status); }

  recompute(): void {
    this.preview = deriveToStatus({
      direction: this.data.direction,
      currentStatus: this.data.status,
      office: this.office,
      eventType: this.eventType,
      requestedToStatus: this.toStatus
    });
  }

  save(): void {
    if (!this.preview.ok) return;
    this.dialogRef.close({
      sample_id_fk: this.data.sample_id_pk,
      event_type: this.eventType,
      office_location: this.office,
      to_status: this.eventType === 'status_change' ? this.toStatus : undefined,
      notes: this.notes || undefined
    });
  }

  cancel(): void { this.dialogRef.close(); }
}

