import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';
import { statusLabel } from '../helpers/sample.status';

// Small thumbnail of the sample's primary photo (or a placeholder icon).
@Component({
  selector: 'sample-photo-renderer',
  standalone: false,
  template: `
    <span class="sample-photo">
      <img *ngIf="url" [src]="url" alt="sample" />
      <mat-icon *ngIf="!url" class="placeholder">photo_camera</mat-icon>
    </span>
  `,
  styles: [`
    .sample-photo { display:flex; align-items:center; justify-content:center; height:100%; }
    .sample-photo img { max-height: 38px; max-width: 70px; border-radius: 4px; object-fit: cover; }
    .sample-photo .placeholder { color: #bdbdbd; }
  `]
})
export class SamplePhotoRendererComponent implements ICellRendererAngularComp {
  url: string | null = null;
  agInit(params: ICellRendererParams): void { this.refresh(params); }
  refresh(params: ICellRendererParams): boolean {
    const data: any = params.data || {};
    this.url = params.value || data.primary_photo || data.thumbnail || null;
    return true;
  }
}

// Status as a coloured chip with a friendly label.
@Component({
  selector: 'sample-status-renderer',
  standalone: false,
  template: `<span class="sample-status-chip" [ngClass]="cls">{{ label }}</span>`,
  styles: [`
    .sample-status-chip { display:inline-block; padding:2px 10px; border-radius:12px; font-size:12px; font-weight:500; }
    .s-neutral { background:#eceff1; color:#37474f; }
    .s-active  { background:#e3f2fd; color:#1565c0; }
    .s-done    { background:#e8f5e9; color:#2e7d32; }
    .s-warn    { background:#fff3e0; color:#e65100; }
    .s-bad     { background:#ffebee; color:#c62828; }
  `]
})
export class SampleStatusRendererComponent implements ICellRendererAngularComp {
  label = '';
  cls = 's-neutral';
  agInit(params: ICellRendererParams): void { this.refresh(params); }
  refresh(params: ICellRendererParams): boolean {
    const status = params.value || '';
    this.label = statusLabel(status);
    this.cls = this.classFor(status);
    return true;
  }
  private classFor(status: string): string {
    if (status === 'cancelled' || status === 'damaged') return 's-bad';
    if (status === 'on_hold') return 's-warn';
    if (status === 'approved' || status === 'nyc_checked_in' || status === 'sent_to_factory') return 's-done';
    if (status && status.indexOf('checked') !== -1 || status === 'shipped') return 's-active';
    return 's-neutral';
  }
}

