import { SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG } from './sample.tracking.config';

describe('sample.tracking.config', () => {
  const cols = SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG.columnDefs as any[];

  it('exposes the expected sample columns', () => {
    const fields = cols.map(c => c.field);
    ['primary_photo', 'sample_name', 'status', 'office_location', 'origin', 'direction',
      'quantity', 'retail_price', 'fob_cost', 'item_id_fk', 'prod_order_no_fk', 'notes']
      .forEach(f => expect(fields).toContain(f));
  });

  it('sets both colId and col_id for every column (layout-system compat)', () => {
    cols.forEach(c => {
      expect(c.colId).toBeDefined();
      expect(c.col_id).toBe(c.colId);
    });
  });

  it('merges commonDefaults — every column is sortable with a cellStyle by default', () => {
    cols.forEach(c => {
      expect(c.cellStyle).toEqual({ 'text-align': 'center' });
    });
  });

  it('uses the group cell renderer on the sample name (master-detail expander)', () => {
    const nameCol = cols.find(c => c.field === 'sample_name');
    expect(nameCol.cellRenderer).toBe('agGroupCellRenderer');
  });

  it('renders status and photo with custom renderers and disables their editing', () => {
    const status = cols.find(c => c.field === 'status');
    const photo = cols.find(c => c.field === 'primary_photo');
    expect(status.cellRenderer).toBe('sampleStatusRenderer');
    expect(status.editable).toBe(false);
    expect(photo.cellRenderer).toBe('samplePhotoRenderer');
    expect(photo.editable).toBe(false);
  });

  it('keeps money columns numeric + editable with a formatter', () => {
