+@Component({
+  selector: 'sample-tracking-link-renderer',
+  standalone: false,
+  template: `
+    <a *ngIf="url; else plain" [href]="url" target="_blank" rel="noopener noreferrer">{{ label }}</a>
+    <ng-template #plain>{{ label }}</ng-template>
+  `,
+  styles: [`
+    a { color:#1565c0; text-decoration: underline; cursor:pointer; }
+  `]
+})
+export class TrackingLinkRendererComponent implements ICellRendererAngularComp {
+  label = '';
+  url: string | null = null;
+
+  agInit(params: ICellRendererParams): void { this.refresh(params); }
+
+  refresh(params: ICellRendererParams): boolean {
+    const data: any = params.data || {};
+    this.label = params.value || '';
+    this.url = trackingUrl(data.courier, this.label);
+    return true;
+  }
+}
+
+export function trackingUrl(courier: string | null | undefined, trackingNumber: string | null | undefined): string | null {
+  const n = String(trackingNumber || '').trim();
+  if (!n) return null;
+  const encoded = encodeURIComponent(n);
+  switch (String(courier || '').toLowerCase()) {
+    case 'ups':
+      return `https://www.ups.com/track?tracknum=${encoded}`;
+    case 'fedex':
+      return `https://www.fedex.com/fedextrack/?trknbr=${encoded}`;
+    case 'aae':
+      return `https://www.aaeexpress.com/track?tracking_number=${encoded}`;
+    case 'bombino':
+      return `https://bombinoexp.com/tracking/?tracking_number=${encoded}`;
+    default:
+      return null;
+  }
+}
