import { trackingUrl } from './sample-cell-renderers';

describe('sample tracking renderers', () => {
  it('builds direct courier tracking links where supported', () => {
    expect(trackingUrl('ups', '1Z999')).toBe('https://www.ups.com/track?tracknum=1Z999');
